INSERT INTO services (slug, category, name_en, name_ar, description_en, description_ar, long_description_en, long_description_ar, features, flow_steps, documents, faqs, icon, sort_order, is_active, created_at, updated_at) VALUES

-- VAT Service
('vat', 'tax',
'VAT Registration & Compliance',
'تسجيل ضريبة القيمة المضافة والامتثال',
'Complete VAT registration and compliance services tailored to your business needs',
'خدمات تسجيل ضريبة القيمة المضافة والامتثال الكاملة المخصصة لاحتياجات عملك',
'Our VAT experts help businesses register with FTA, manage monthly/quarterly filings, optimize input VAT recovery, and ensure continuous compliance. We handle all aspects of VAT management from registration to audit preparation, ensuring your business remains compliant while maximizing tax efficiency.',
'يساعد خبراؤنا في ضريبة القيمة المضافة الشركات على التسجيل لدى FTA وإدارة الإقرارات الشهرية والربع سنوية وتحسين استرجاع ضريبة المدخلات والامتثال المستمر. نتعامل مع جميع جوانب إدارة ضريبة القيمة المضافة من التسجيل إلى تحضير التدقيق، مما يضمن بقاء عملك متوافقاً مع الكفاءة الضريبية القصوى.',
'[{"title_en":"Expert FTA Registration","title_ar":"تسجيل FTA الخبير","description_en":"Seamless registration with Federal Tax Authority","description_ar":"تسجيل سلس لدى سلطة الضرائب الفيدرالية"},{"title_en":"Monthly/Quarterly Filings","title_ar":"الإقرارات الشهرية والربع سنوية","description_en":"Timely and accurate tax return submissions","description_ar":"تقديم إقرارات ضريبية دقيقة وفي الوقت المناسب"},{"title_en":"Input VAT Recovery","title_ar":"استرجاع ضريبة المدخلات","description_en":"Maximize legitimate tax credits","description_ar":"تحقيق أقصى استفادة من الأرصدة الضريبية المشروعة"},{"title_en":"Audit Support","title_ar":"دعم التدقيق","description_en":"Comprehensive audit preparation and representation","description_ar":"تحضير شامل للتدقيق والتمثيل"}]',
'[{"step":1,"title_en":"Business Assessment","title_ar":"تقييم الأعمال","description_en":"Evaluate VAT obligation based on turnover","description_ar":"تقييم التزام ضريبة القيمة المضافة بناءً على الإيرادات"},{"step":2,"title_en":"Registration Application","title_ar":"طلب التسجيل","description_en":"Submit FTA registration forms and documentation","description_ar":"تقديم نماذج التسجيل والوثائق"},{"step":3,"title_en":"System Setup","title_ar":"إعداد النظام","description_en":"Configure accounting systems for VAT tracking","description_ar":"تكوين الأنظمة المحاسبية لتتبع ضريبة القيمة المضافة"},{"step":4,"title_en":"Monthly Compliance","title_ar":"الامتثال الشهري","description_en":"Ongoing returns and compliance management","description_ar":"إدارة الإقرارات المستمرة والامتثال"}]',
'[{"name":"VAT Application Forms","name_ar":"نماذج التطبيق"},{"name":"Business License","name_ar":"رخصة العمل"},{"name":"Financial Statements","name_ar":"البيانات المالية"}]',
'[{"question_en":"What is the VAT threshold in UAE?","question_ar":"ما هو حد ضريبة القيمة المضافة في الإمارات؟","answer_en":"Businesses with annual turnover exceeding AED 375,000 must register for VAT","answer_ar":"يجب على الشركات التي يتجاوز دخلها السنوي 375 ألف درهم التسجيل لضريبة القيمة المضافة"},{"question_en":"How often should VAT returns be filed?","question_ar":"كم مرة يجب تقديم إقرارات ضريبة القيمة المضافة؟","answer_en":"Monthly or quarterly depending on your annual turnover and election","answer_ar":"شهري أو ربع سنوي حسب دخلك السنوي والخيار المختار"}]',
'receipt',
1, TRUE, NOW(), NOW()),

-- Corporate Tax Service
('corporate-tax', 'tax',
'Corporate Income Tax',
'ضريبة دخل الشركات',
'Strategic corporate tax planning and compliance for UAE businesses',
'تخطيط ضريبة دخل الشركات الاستراتيجي والامتثال للشركات الإماراتية',
'Navigate UAE corporate tax requirements with confidence. Our team provides strategic tax planning, helps optimize your tax position, prepares annual corporate tax returns, and ensures compliance with all FTA requirements. We work with your financial team to identify tax-efficient structures and opportunities.',
'تنقل متطلبات ضريبة دخل الشركات الإماراتية بثقة. يقدم فريقنا تخطيط ضريبي استراتيجي ويساعد في تحسين موقفك الضريبي وتحضير إقرارات ضريبة دخل الشركات السنوية والامتثال لجميع متطلبات FTA. نعمل مع فريقك المالي لتحديد الهياكل الفعالة من حيث الضرائب والفرص.',
'[{"title_en":"Tax Planning","title_ar":"التخطيط الضريبي","description_en":"Strategic optimization of tax position","description_ar":"التحسين الاستراتيجي للموقف الضريبي"},{"title_en":"Return Preparation","title_ar":"تحضير الإقرار","description_en":"Accurate annual corporate tax returns","description_ar":"إقرارات ضريبة دخل الشركات السنوية الدقيقة"},{"title_en":"Compliance","title_ar":"الامتثال","description_en":"Full FTA compliance and documentation","description_ar":"الامتثال الكامل لـ FTA والتوثيق"},{"title_en":"Appeals","title_ar":"الاستئنافات","description_en":"Tax dispute resolution and representation","description_ar":"حل نزاعات الضرائب والتمثيل"}]',
'[{"step":1,"title_en":"Financial Review","title_ar":"مراجعة مالية","description_en":"Comprehensive analysis of financial statements","description_ar":"تحليل شامل للبيانات المالية"},{"step":2,"title_en":"Tax Position Analysis","title_ar":"تحليل الموقف الضريبي","description_en":"Identify tax risks and opportunities","description_ar":"تحديد مخاطر الضرائب والفرص"},{"step":3,"title_en":"Return Preparation","title_ar":"تحضير الإقرار","description_en":"Prepare and file corporate tax return","description_ar":"تحضير وتقديم إقرار ضريبة الشركات"},{"step":4,"title_en":"Documentation","title_ar":"التوثيق","description_en":"Maintain compliance records and documentation","description_ar":"الحفاظ على سجلات الامتثال والتوثيق"}]',
'[{"name":"Financial Statements","name_ar":"البيانات المالية"},{"name":"Trial Balance","name_ar":"ميزان المراجعة"},{"name":"Supporting Documentation","name_ar":"الوثائق الداعمة"}]',
'[{"question_en":"What is the corporate tax rate in UAE?","question_ar":"ما هو معدل ضريبة دخل الشركات في الإمارات؟","answer_en":"UAE has a 0% corporate tax rate for most businesses, except for certain sectors like oil & gas","answer_ar":"الإمارات لديها معدل ضريبة دخل شركات بنسبة 0% لمعظم الشركات، باستثناء قطاعات معينة مثل النفط والغاز"},{"question_en":"When is the corporate tax return due?","question_ar":"متى يستحق تقديم إقرار ضريبة دخل الشركات؟","answer_en":"Returns are typically due 90 days after the end of the tax year","answer_ar":"عادة ما تكون الإقرارات مستحقة في غضون 90 يوماً بعد نهاية السنة الضريبية"}]',
'briefcase',
2, TRUE, NOW(), NOW()),

-- Excise Tax Service
('excise-tax', 'tax',
'Excise Tax Management',
'إدارة ضريبة الاستهلاك',
'Excise tax compliance and management for regulated industries',
'امتثال إدارة ضريبة الاستهلاك للصناعات المنظمة',
'If your business handles excisable goods (tobacco, energy drinks, carbonated beverages, etc.), our experts ensure proper excise tax registration, calculation, and timely compliance filings. We help you understand excise obligations and implement compliant operational procedures.',
'إذا كان عملك يتعامل مع السلع الخاضعة للاستهلاك (التبغ والمشروبات الطاقية والمشروبات الغازية وغيرها)، يضمن خبراؤنا التسجيل الصحيح لضريبة الاستهلاك والحساب والامتثال لتقديم الإقرارات في الوقت المناسب. نساعدك على فهم التزامات الاستهلاك وتنفيذ إجراءات تشغيلية متوافقة.',
'[{"title_en":"Excise Registration","title_ar":"تسجيل الاستهلاك","description_en":"Register with authorities for excisable goods","description_ar":"التسجيل مع السلطات للسلع الخاضعة للاستهلاك"},{"title_en":"Tax Calculation","title_ar":"حساب الضريبة","description_en":"Accurate excise tax rate application","description_ar":"تطبيق معدل ضريبة الاستهلاك الدقيق"},{"title_en":"Quarterly Filings","title_ar":"الإقرارات ربع السنوية","description_en":"Timely excise tax return submissions","description_ar":"تقديم إقرارات ضريبة الاستهلاك في الوقت المناسب"},{"title_en":"Audit Support","title_ar":"دعم التدقيق","description_en":"Defense in excise tax audits","description_ar":"الدفاع في تدقيق ضريبة الاستهلاك"}]',
'[{"step":1,"title_en":"Business Assessment","title_ar":"تقييم الأعمال","description_en":"Identify excisable products in your portfolio","description_ar":"تحديد المنتجات الخاضعة للاستهلاك في محفظتك"},{"step":2,"title_en":"Registration","title_ar":"التسجيل","description_en":"Register as excise taxpayer with FTA","description_ar":"التسجيل كدافع ضريبة استهلاك مع FTA"},{"step":3,"title_en":"System Setup","title_ar":"إعداد النظام","description_en":"Configure tracking and reporting systems","description_ar":"تكوين أنظمة التتبع والإبلاغ"},{"step":4,"title_en":"Ongoing Compliance","title_ar":"الامتثال المستمر","description_en":"Manage quarterly returns and audits","description_ar":"إدارة الإقرارات ربع السنوية والتدقيق"}]',
'[{"name":"Product Inventory","name_ar":"قائمة جرد المنتجات"},{"name":"Sales Records","name_ar":"سجلات المبيعات"},{"name":"Tax Calculations","name_ar":"حسابات الضرائب"}]',
'[{"question_en":"Which products are subject to excise tax?","question_ar":"ما هي المنتجات الخاضعة لضريبة الاستهلاك؟","answer_en":"Tobacco, energy drinks, carbonated beverages, and certain electronic products are subject to excise tax","answer_ar":"التبغ والمشروبات الطاقية والمشروبات الغازية والمنتجات الإلكترونية معينة تخضع لضريبة الاستهلاك"}]',
'percentage',
3, TRUE, NOW(), NOW());

-- Accounting Services - Accounting Category
INSERT INTO services (slug, category, name_en, name_ar, description_en, description_ar, long_description_en, long_description_ar, features, flow_steps, documents, faqs, icon, sort_order, is_active, created_at, updated_at) VALUES

('accounting-services', 'accounting',
'Full Accounting Services',
'خدمات المحاسبة الكاملة',
'Comprehensive bookkeeping and accounting solutions for all business sizes',
'حلول محاسبة وتسجيل دفاتر شاملة لجميع أحجام الأعمال',
'From daily bookkeeping to annual financial statements, our accounting team handles all aspects of financial record-keeping. We use modern accounting software, maintain compliance with UAE accounting standards, prepare monthly management accounts, and ensure your financial records are accurate and audit-ready.',
'من التسجيل اليومي إلى البيانات المالية السنوية، يتعامل فريق محاسباتنا مع جميع جوانب الحفاظ على السجلات المالية. نستخدم برامج محاسبية حديثة، والامتثال للمعايير المحاسبية الإماراتية، وتحضير حسابات الإدارة الشهرية، والتأكد من دقة سجلاتك المالية وجاهزيتها للتدقيق.',
'[{"title_en":"Daily Bookkeeping","title_ar":"التسجيل اليومي","description_en":"Recording all transactions and entries","description_ar":"تسجيل جميع المعاملات والقيود"},{"title_en":"Month-End Close","title_ar":"إغلاق نهاية الشهر","description_en":"Monthly reconciliation and closing procedures","description_ar":"المصالحة الشهرية وإجراءات الإغلاق"},{"title_en":"Financial Reporting","title_ar":"التقارير المالية","description_en":"Management accounts and financial statements","description_ar":"حسابات الإدارة والبيانات المالية"},{"title_en":"Payroll Processing","title_ar":"معالجة الرواتب","description_en":"Employee payroll and government compliance","description_ar":"رواتب الموظفين والامتثال الحكومي"}]',
'[{"step":1,"title_en":"Initial Setup","title_ar":"الإعداد الأولي","description_en":"Configure accounting systems and chart of accounts","description_ar":"تكوين الأنظمة المحاسبية وخطة الحسابات"},{"step":2,"title_en":"Transaction Processing","title_ar":"معالجة المعاملات","description_en":"Daily recording of invoices, payments, and receipts","description_ar":"التسجيل اليومي للفواتير والدفعات والإيصالات"},{"step":3,"title_en":"Bank Reconciliation","title_ar":"مصالحة البنك","description_en":"Regular bank account reconciliation","description_ar":"مصالحة حسابات البنك بانتظام"},{"step":4,"title_en":"Financial Statements","title_ar":"البيانات المالية","description_en":"Prepare monthly P&L and balance sheet","description_ar":"تحضير بيان الدخل والميزانية العمومية الشهرية"}]',
'[{"name":"Bank Statements","name_ar":"كشوف الحسابات البنكية"},{"name":"Invoices","name_ar":"الفواتير"},{"name":"Expense Receipts","name_ar":"إيصالات النفقات"},{"name":"Payroll Records","name_ar":"سجلات الرواتب"}]',
'[{"question_en":"How often should accounting records be updated?","question_ar":"كم مرة يجب تحديث السجلات المحاسبية؟","answer_en":"Transactions should be recorded daily for accurate financial management","answer_ar":"يجب تسجيل المعاملات يومياً للإدارة المالية الدقيقة"},{"question_en":"What accounting standards apply in UAE?","question_ar":"ما هي معايير المحاسبة المعمول بها في الإمارات؟","answer_en":"UAE companies must follow IFRS (International Financial Reporting Standards)","answer_ar":"يجب على شركات الإمارات اتباع IFRS (معايير الإبلاغ المالي الدولية)"}]',
'calculator',
4, TRUE, NOW(), NOW()),

('bookkeeping-services', 'accounting',
'Professional Bookkeeping',
'التسجيل الاحترافي',
'Accurate and timely bookkeeping for your business',
'التسجيل الدقيق والفي الوقت المناسب لعملك',
'Keep your financial records clean and compliant with our professional bookkeeping services. Whether you need part-time bookkeeper support or full-service accounting, we ensure every transaction is properly recorded, categorized, and reconciled.',
'احتفظ بسجلاتك المالية نظيفة ومتوافقة مع خدمات التسجيل الاحترافية لدينا. سواء كنت بحاجة إلى دعم محاسب بدوام جزئي أو خدمات محاسبية كاملة، فإننا نضمن تسجيل كل معاملة بشكل صحيح وتصنيفها ومصالحتها.',
'[{"title_en":"Daily Entry Recording","title_ar":"تسجيل القيود اليومية","description_en":"All transactions recorded accurately","description_ar":"تسجيل جميع المعاملات بدقة"},{"title_en":"Bank Reconciliation","title_ar":"مصالحة البنك","description_en":"Monthly bank account matching","description_ar":"مطابقة حساب البنك الشهرية"},{"title_en":"Invoice Management","title_ar":"إدارة الفواتير","description_en":"Receivables and payables tracking","description_ar":"تتبع الذمم المدينة والدائنة"},{"title_en":"Trial Balance","title_ar":"ميزان المراجعة","description_en":"Monthly account verification","description_ar":"التحقق من الحساب الشهري"}]',
'[{"step":1,"title_en":"Account Setup","title_ar":"إعداد الحساب","description_en":"Configure chart of accounts","description_ar":"تكوين خطة الحسابات"},{"step":2,"title_en":"Data Entry","title_ar":"إدخال البيانات","description_en":"Record daily transactions","description_ar":"تسجيل المعاملات اليومية"},{"step":3,"title_en":"Verification","title_ar":"التحقق","description_en":"Review and verify entries","description_ar":"مراجعة والتحقق من القيود"},{"step":4,"title_en":"Reporting","title_ar":"الإبلاغ","description_en":"Generate monthly reports","description_ar":"إنشاء التقارير الشهرية"}]',
'[{"name":"Transaction Records","name_ar":"سجلات المعاملات"},{"name":"Bank Statements","name_ar":"كشوف الحسابات البنكية"},{"name":"Receipts and Invoices","name_ar":"الإيصالات والفواتير"}]',
'[{"question_en":"Can you handle multiple currencies?","question_ar":"هل يمكنك التعامل مع عملات متعددة؟","answer_en":"Yes, we manage transactions in AED, USD, and other currencies with proper FX treatment","answer_ar":"نعم، نتعامل مع المعاملات بالدرهم والدولار والعملات الأخرى مع معاملة الصرف الأجنبي الصحيحة"}]',
'document',
5, TRUE, NOW(), NOW()),

('internal-auditing', 'accounting',
'Internal Audit Services',
'خدمات التدقيق الداخلي',
'Strengthen controls and operations with internal audit',
'تقوية الضوابط والعمليات مع التدقيق الداخلي',
'Our internal audit specialists help identify risks, evaluate internal controls, and improve operational efficiency. We conduct comprehensive internal audits that provide management with actionable insights to strengthen your organization.',
'يساعد متخصصو التدقيق الداخلي لدينا على تحديد المخاطر وتقييم الضوابط الداخلية وتحسين الكفاءة التشغيلية. نجري تدقيق داخلي شامل يزود الإدارة برؤى قابلة للتنفيذ لتقوية مؤسستك.',
'[{"title_en":"Risk Assessment","title_ar":"تقييم المخاطر","description_en":"Identify operational and financial risks","description_ar":"تحديد مخاطر تشغيلية ومالية"},{"title_en":"Control Testing","title_ar":"اختبار الضوابط","description_en":"Evaluate effectiveness of controls","description_ar":"تقييم فعالية الضوابط"},{"title_en":"Audit Report","title_ar":"تقرير التدقيق","description_en":"Detailed findings and recommendations","description_ar":"النتائج والتوصيات التفصيلية"},{"title_en":"Follow-up","title_ar":"المتابعة","description_en":"Track implementation of recommendations","description_ar":"تتبع تنفيذ التوصيات"}]',
'[{"step":1,"title_en":"Audit Planning","title_ar":"تخطيط التدقيق","description_en":"Define scope and objectives","description_ar":"تحديد النطاق والأهداف"},{"step":2,"title_en":"Fieldwork","title_ar":"العمل الميداني","description_en":"Execute audit procedures","description_ar":"تنفيذ إجراءات التدقيق"},{"step":3,"title_en":"Analysis","title_ar":"التحليل","description_en":"Analyze findings and control gaps","description_ar":"تحليل النتائج والفجوات في الضوابط"},{"step":4,"title_en":"Reporting","title_ar":"الإبلاغ","description_en":"Issue audit report with recommendations","description_ar":"إصدار تقرير التدقيق مع التوصيات"}]',
'[{"name":"Audit Plan","name_ar":"خطة التدقيق"},{"name":"Internal Controls Documentation","name_ar":"توثيق الضوابط الداخلية"},{"name":"Process Documentation","name_ar":"توثيق العملية"}]',
'[{"question_en":"What is the difference between internal and external audit?","question_ar":"ما الفرق بين التدقيق الداخلي والخارجي؟","answer_en":"Internal audit focuses on improving operations and controls; external audit verifies financial statement accuracy","answer_ar":"يركز التدقيق الداخلي على تحسين العمليات والضوابط؛ يتحقق التدقيق الخارجي من دقة البيانات المالية"}]',
'shield',
6, TRUE, NOW(), NOW()),

('external-auditing', 'accounting',
'External Audit Services',
'خدمات التدقيق الخارجي',
'Professional external audit for financial statement assurance',
'التدقيق الخارجي الاحترافي لتأكيد البيانات المالية',
'Get independent assurance of your financial statements through our external audit services. Our certified auditors provide credibility to your financial reporting and help you meet statutory and regulatory requirements.',
