-- Seed FAQs table
INSERT INTO faqs (question_en, question_ar, answer_en, answer_ar, category, sort_order, is_active, created_at) VALUES

('What is the UAE corporate tax rate?', 'ما هو معدل ضريبة دخل الشركات في الإمارات؟',
'The UAE does not levy corporate income tax on most businesses. However, certain sectors like oil and gas, and foreign companies in free zones are subject to 0% to various rates depending on circumstances.',
'لا تفرض الإمارات ضريبة دخل على معظم الشركات. ومع ذلك، تخضع القطاعات معينة مثل النفط والغاز والشركات الأجنبية في المناطق الحرة لمعدلات من 0% إلى معدلات مختلفة حسب الظروف.',
'tax', 1, TRUE, NOW()),

('Do I need to register for VAT if my turnover is below the threshold?', 'هل أحتاج إلى التسجيل لضريبة القيمة المضافة إذا كان دخلي أقل من الحد؟',
'Registration is mandatory if your annual turnover exceeds AED 375,000. If below this threshold, registration is optional but can be advantageous for input VAT recovery.',
'التسجيل إلزامي إذا تجاوز دخلك السنوي 375 ألف درهم. إذا كان أقل من هذا الحد، فإن التسجيل اختياري لكن يمكن أن يكون مفيداً لاسترجاع ضريبة المدخلات.',
'tax', 2, TRUE, NOW()),

('What records must I maintain for FTA compliance?', 'ما السجلات التي يجب أن أحتفظ بها للامتثال لـ FTA؟',
'You must maintain invoices, receipts, bank statements, expense documentation, payroll records, and VAT return copies for minimum 5 years. All records must be in Arabic and English.',
'يجب عليك الاحتفاظ بالفواتير والإيصالات وكشوف الحسابات البنكية وتوثيق النفقات وسجلات الرواتب ونسخ إقرارات ضريبة القيمة المضافة لمدة 5 سنوات على الأقل. يجب أن تكون جميع السجلات باللغة العربية والإنجليزية.',
'tax', 3, TRUE, NOW()),

('How can Sage help with a tax audit?', 'كيف يمكن لـ Sage أن تساعد في تدقيق الضرائب؟',
'We provide complete audit support including document preparation, responding to FTA inquiries, representing you in meetings, and defending your tax position. We work to minimize adjustments and resolve disputes efficiently.',
'نوفر دعم تدقيق شامل بما في ذلك تحضير الوثائق والرد على استفسارات سلطة الضرائب الفيدرالية والتمثيل في الاجتماعات والدفاع عن موقفك الضريبي. نعمل على تقليل التعديلات وحل النزاعات بكفاءة.',
'tax', 4, TRUE, NOW()),

('Do free zone companies have to pay corporate tax?', 'هل شركات المناطق الحرة مضطرة لدفع ضريبة دخل الشركات؟',
'Most free zone companies are exempt from corporate income tax. However, they must still comply with VAT registration if turnover exceeds thresholds and must maintain proper accounting records.',
'معظم شركات المناطق الحرة معفاة من ضريبة دخل الشركات. ومع ذلك، يجب عليهم الامتثال لتسجيل ضريبة القيمة المضافة إذا تجاوز الدخل الحدود والحفاظ على سجلات محاسبية مناسبة.',
'tax', 5, TRUE, NOW());
